  program3.addCommand(createImageCommand());
  program3.addCommand(createVideoCommand());
  program3.addCommand(createVoiceCommand());
  program3.addCommand(createAudioCommand());
  program3.addCommand(createConfigCommand());
  program3.addCommand(createProvidersCommand());
  program3.addCommand(createSkillCommand());
  program3.addCommand(createJobCommand());
